penpot.ui.open("ColorSlurp Importer","https://janstieler.github.io/penpot-colorslurp-importer/dist/index.html",{width:400,height:560});penpot.ui.onMessage(t=>{if(t.type==="get-library-colors"){const e=penpot.library.local.colors.map(o=>({name:o.name}));penpot.ui.sendMessage({type:"library-colors",colors:e})}if(t.type==="import-colors"){const{colors:e}=t;for(const o of e){const r=penpot.library.local.createColor();r.name=o.name,r.color=o.hex,r.opacity=o.alpha}penpot.ui.sendMessage({type:"done",count:e.length})}});
